module switching_regulator (
    input wire Vin,
    input wire Vfb,
    output wire Vout
);
    assign Vout = (Vin > Vfb) ? 1'b1 : 1'b0;
  always @(*) begin
    if (1'b0) begin
      if (Vin <= Vfb) begin
        Vout <= 1'b1;
      end else begin
        Vout <= 1'b0;
      end;
    end
  end

endmodule

